const controlName = env.get('control_name');
const value = Number(env.get('value'));
const chip = Number(env.get('chip'));
const pinMapStr = env.get('pin_map');
const helperPath = env.get('helper_path');

if (!helperPath) { node.error('helper_path env var must be set', msg); return null; }
if (![0, 1].includes(value)) { node.error('value must be 0 or 1', msg); return null; }

// Parse pin map: 'name=pin,name=pin,...' → {name: pin, ...}
const pinMap = {};
for (const entry of pinMapStr.split(',')) {
    const [k, v] = entry.split('=');
    if (k && v) pinMap[k.trim()] = Number(v.trim());
}

const pin = pinMap[controlName];
if (pin === undefined || isNaN(pin)) {
    node.error(`control_name '${controlName}' not found in pin_map`, msg);
    return null;
}

msg._cfg = { controlName, value, chip, pin };
msg.payload = `python3 ${helperPath} write --chip ${chip} --pin ${pin} --value ${value}`;
return msg;

const rc = msg.rc && typeof msg.rc.code === 'number' ? msg.rc.code : null;
const text = (typeof msg.payload === 'string') ? msg.payload : '';

if (rc === null) {
    msg._buf = (msg._buf || '') + text;
    return null;
}

const output = (msg._buf || '').trim();
try {
    const result = JSON.parse(output);
    msg.payload = {
        control_name: msg._cfg.controlName,
        commanded: msg._cfg.value,
        chip: msg._cfg.chip,
        pin: msg._cfg.pin,
        success: result.success,
        timestamp: new Date().toISOString()
    };
} catch (e) {
    msg.payload = {
        control_name: msg._cfg.controlName,
        success: false,
        error: `could not parse: ${output}`,
        timestamp: new Date().toISOString()
    };
}

delete msg._cfg;
delete msg._buf;
return msg;
